tor-tools", "meta": {"h": "competitor-tools", "gp": "https://www.patreon.com/hogmobministries", "tool": "patreon", "import_source": "import_batch_4.sql"}}, {"org_name": "Orchard Resources Inc (Ignite Monthly)", "org_type": "organization", "website": "classy.org/campaign/ignite-monthly-giving/c457848", "city": null, "state": null, "summary": "Atlanta 501(c)(3) empowering donors to support Christian leaders launching ministries that serve those in need; monthly giving program (''''Ignite Monthly'''') runs on Classy with manual email/check workflows for DAF and check donors. | Field: US (empowers Christian leaders launching ministrie | Comms: Classy campaign receipts/emails (ongoing monthly; dates not verified)", "fit_score": 6, "fit_reason": "Small Christian org running recurring giving on Classy with visibly manual donor operations (email us for checks/DAF).", "source_query": "hunter:competitor-tools", "meta": {"h": "competitor-tools", "gp": "https://giving.classy.org/campaign/642177/donate", "tool": "classy", "import_source": "import_batch_4.sql"}}, {"org_name": "Thang''''s Missionary Support (Children''''s Bible Ministries)", "org_type": "individual", "website": "childrensbibleministries.net", "city": null, "state": null, "summary": "Thang (CBM staff missionary) | Individual staff missionary with Children''''s Bible Ministries raising personal support through a Zeffy peer-to-peer campaign (same sending org as the Austins). | Field: US-based with international affiliate ministry | Comms: Zeffy peer-to-peer page (dates not verified)", "fit_score": 7, "fit_reason": "Another individually support-raised CBM worker on Zeffy peer-to-peer \u2014 same proven pain point and sending-org cluster.", "source_query": "hunter:competitor-tools", "meta": {"h": "competitor-tools", "gp": "https://www.zeffy.com/en-US/peer-to-peer/thangs-missionary-support", "tool": "zeffy", "import_source": "import_batch_4.sql"}}, {"org_name": "Crossculture Note - Fr. Christopher Vorderbruggen", "org_type": "individual", "website": "buymeacoffee.com/fatherchris", "city": null, "state": null, "summary": "Fr. Christopher Vorderbruggen | Missionary priest and writer sharing daily reflections, scripture threads, and spiritual direction online, supported by one-time and recurring gifts on Buy Me a Coffee. | Field: US/online (missionary priest, daily reflections) | Comms: Buy Me a Coffee posts / daily online reflections (dates not verified)", "fit_score": 6, "fit_reason": "Individual ministry worker funding ministry through a generic tip platform with no donor management.", "source_query": "hunter:competitor-tools", "meta": {"h": "competitor-tools", "gp": "https://buymeacoffee.com/fatherchris", "tool": "buymeacoffee", "import_source": "import_batch_4.sql"}}]'::jsonb)
  as x(org_name text, org_type text, website text, city text, state text,
       summary text, fit_score int, fit_reason text, source_query text, meta jsonb)),
-- Count how many existing rows (queue + pipeline) share each URL.
-- A URL on exactly one row is a person-specific page safe to dedup
-- against; a URL shared by many is a roster/platform page and must
-- NOT cause a skip, or we'd drop distinct people who list it.
existing_sites as (
  select site, count(*) as n from (
    select rtrim(lower(regexp_replace(website, '^https?://(www\.)?', '', 'i')), '/') as site
      from sales.scout_candidates where website is not null and btrim(website) <> ''
    union all
    select rtrim(lower(regexp_replace(website, '^https?://(www\.)?', '', 'i')), '/') as site
      from sales.leads where website is not null and btrim(website) <> ''
  ) w group by site)
insert into sales.scout_candidates
  (org_name, org_type, website, city, state, summary,
   fit_score, fit_reason, source_query, status, meta)
select s.org_name, s.org_type, s.website, s.city, s.state, s.summary,
       s.fit_score, s.fit_reason, s.source_query, 'pending', coalesce(s.meta, '{}'::jsonb)
from src s
where not exists (select 1 from sales.scout_candidates c
                  where lower(trim(c.org_name)) = lower(trim(s.org_name)))
  and not exists (select 1 from sales.leads l
                  where lower(trim(l.org_name)) = lower(trim(s.org_name)))
  and not exists (select 1 from existing_sites es
                  where s.website is not null and btrim(s.website) <> ''
                    and es.n = 1
                    and es.site = rtrim(lower(regexp_replace(s.website, '^https?://(www\.)?', '', 'i')), '/'));